    // Verify deletion
    expect(result.recordsDeleted).toBeGreaterThan(0);

    const records = await lookupCPF(cpf);
    expect(records).toHaveLength(0);

    // Verify audit trail exists
    const audit = await dynamodb.get({
      TableName: 'lgpd_deletion_audit',
      Key: { audit_id: result.auditId }
    });
    expect(audit.Item.status).toBe('COMPLETED');
  });

  it('should not log CPF in CloudWatch', async () => {
    // Mock console.log to capture logs
    const logs: string[] = [];
