      logs.push(JSON.stringify(args));
    });

    await processFailure({ cpf: '12345678900' });

    logs.forEach(log => {
      expect(log).not.toMatch(/\d{11}/);  // No 11-digit sequences
      expect(log).not.toMatch(/\d{3}\.\d{3}\.\d{3}-\d{2}/);  // No formatted CPF
    });
  });
});
```

